{# skeleton/config/settings.yaml.njk #}
service_name: ${{ values.name }}
log_level: INFO
default_model: ${{ values.llmModels[0] }}
max_tokens: 2048
temperature: 0.0
eval_pass_threshold: ${{ values.evalThreshold }}

{% if values.ragEnabled %}
vector_store:
  type: pgvector
  table: embeddings_${{ values.name | replace('-', '_') }}
  embedding_model: text-embedding-3-small
  top_k: 5
{% endif %}

{% if values.streamingEnabled %}
streaming:
  enabled: true
  timeout_seconds: 60
  buffer_size_tokens: 20
{% endif %}

{# skeleton/src/app/main.py.njk #}
from fastapi import FastAPI
from contextlib import asynccontextmanager
from src.app.config import settings
from src.app.router import router
{% if values.ragEnabled %}
from src.models.retrieval import VectorStore
{% endif %}

@asynccontextmanager
async def lifespan(app: FastAPI):
    {% if values.ragEnabled %}
    app.state.vector_store = VectorStore.from_settings(settings)
    await app.state.vector_store.connect()
    {% endif %}
    yield
    {% if values.ragEnabled %}
    await app.state.vector_store.close()
    {% endif %}

app = FastAPI(title="${{ values.name }}", lifespan=lifespan)
app.include_router(router, prefix="/api/v1")

// packages/backend/src/plugins/scaffolder/actions/checkNameAvailable.ts
import { createTemplateAction } from '@backstage/plugin-scaffolder-node';
import fetch from 'node-fetch';

export const checkNameAvailableAction = () =>
  createTemplateAction<{ name: string; catalogBaseUrl: string }>({
    id: 'platform:catalog:check-name-available',
    description: 'Fails if a catalog entity with the given name already exists',
    schema: {
      input: {
        required: ['name'],
        type: 'object',
        properties: {
          name: { type: 'string', title: 'Entity name to check' },
        },
      },
    },
    async handler(ctx) {
      const { name } = ctx.input;
      const url = `${ctx.baseUrl}/api/catalog/entities/by-name/component/default/${name}`;
      const res = await fetch(url, {
        headers: { Authorization: `Bearer ${ctx.secrets?.backstageToken}` },
      });
      if (res.ok) {
        throw new Error(
          \`Service name '\${name}' is already taken. Choose a different name.\`
        );
      }
      if (res.status !== 404) {
        throw new Error(\`Unexpected status \${res.status} checking name availability\`);
      }
      ctx.logger.info(\`Name '\${name}' is available\`);
    },
  });

// packages/backend/src/plugins/scaffolder.ts
import { createRouter } from '@backstage/plugin-scaffolder-backend';
import { checkNameAvailableAction } from './actions/checkNameAvailable';
import { provisionLlmCredentialAction } from './actions/provisionLlmCredential';

export async function createPlugin(env: PluginEnvironment) {
  return createRouter({
    logger: env.logger,
    config: env.config,
    database: env.database,
    reader: env.reader,
    catalogClient: new CatalogClient({ discoveryApi: env.discovery }),
    additionalTemplateFilters: {},
    additionalTemplateGlobals: {},
    actions: [
      ...createBuiltinActions({ ... }),
      checkNameAvailableAction(),
      provisionLlmCredentialAction(),
    ],
  });
}

// packages/backend/src/plugins/scaffolder/actions/provisionLlmCredential.ts
import { createTemplateAction } from '@backstage/plugin-scaffolder-node';
import fetch from 'node-fetch';

export const provisionLlmCredentialAction = () =>
  createTemplateAction<{
    serviceName: string;
    ownerTeam: string;
    models: string[];
    lifecycle: string;
  }>({
    id: 'platform:llm-gateway:provision-credential',
    description: 'Create a scoped LLM gateway credential for the new service',
    schema: {
      input: {
        required: ['serviceName', 'ownerTeam', 'models'],
        type: 'object',
        properties: {
          serviceName: { type: 'string' },
          ownerTeam:   { type: 'string' },
          models:      { type: 'array', items: { type: 'string' } },
          lifecycle:   { type: 'string', default: 'experimental' },
        },
      },
      output: {
        type: 'object',
        properties: {
          credentialSecretName: { type: 'string' },
        },
      },
    },
    async handler(ctx) {
      const limits = ctx.input.lifecycle === 'production'
        ? { tokens_per_day: 10_000_000, rpm: 500 }
        : { tokens_per_day: 500_000,   rpm: 60 };

      const res = await fetch(
        `${ctx.secrets?.llmGatewayUrl}/api/v1/credentials`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${ctx.secrets?.llmGatewayAdminToken}`,
          },
          body: JSON.stringify({
            name: `svc-${ctx.input.serviceName}`,
            owner: ctx.input.ownerTeam,
            models: ctx.input.models,
            limits,
            labels: { service: ctx.input.serviceName },
          }),
        }
      );
      if (!res.ok) throw new Error(\`Gateway provision failed: \${res.status}\`);
      const { secret_name } = await res.json() as { secret_name: string };

      ctx.logger.info(\`LLM credential provisioned: \${secret_name}\`);
      ctx.output('credentialSecretName', secret_name);
    },
  });

- id: notify-slack
  name: Notify team Slack channel
  action: http:backstage:request
  input:
    method: POST
    path: /api/platform/notify/slack
    body:
      channel: ${{ parameters.slackChannel }}
      text: |
        :rocket: New GenAI service scaffolded: *${{ parameters.name }}*
        Owner: ${{ parameters.owner }}
        Models: ${{ parameters.llmModels | join(', ') }}
        Repo: https://github.com/myorg/${{ parameters.name }}
        Catalog: https://backstage.internal/catalog/default/component/${{ parameters.name }}
        LLM credential: ${{ steps['provision-llm-cred'].output.credentialSecretName }}
